<?php if ( ! defined( 'ABSPATH' ) ) exit; ?>
<div class="qm2026 qm2026-ranking"><h2><?php esc_html_e('Ranking',QM2026_TEXT_DOMAIN); ?></h2><div class="qm2026-table-wrap"><table><thead><tr><th><?php esc_html_e('Pos.',QM2026_TEXT_DOMAIN); ?></th><th><?php esc_html_e('Participante',QM2026_TEXT_DOMAIN); ?></th><th><?php esc_html_e('Puntos',QM2026_TEXT_DOMAIN); ?></th><th><?php esc_html_e('Exactos',QM2026_TEXT_DOMAIN); ?></th><th><?php esc_html_e('Ganadores',QM2026_TEXT_DOMAIN); ?></th><th><?php esc_html_e('Dif. acum.',QM2026_TEXT_DOMAIN); ?></th></tr></thead><tbody><?php foreach($ranking as $row): ?><tr><td><?php echo esc_html($row->position); ?></td><td><?php echo esc_html($row->name); ?></td><td><strong><?php echo esc_html($row->total_points); ?></strong></td><td><?php echo esc_html($row->exact_scores); ?></td><td><?php echo esc_html($row->winners_correct); ?></td><td><?php echo esc_html($row->goal_diff_abs); ?></td></tr><?php endforeach; if(empty($ranking)): ?><tr><td colspan="6"><?php esc_html_e('Aún no hay participantes.',QM2026_TEXT_DOMAIN); ?></td></tr><?php endif; ?></tbody></table></div><p class="qm2026-muted"><?php printf(esc_html__('Última actualización: %s',QM2026_TEXT_DOMAIN),esc_html(date_i18n(get_option('date_format').' '.get_option('time_format')))); ?></p></div>
